package string;

import java.util.HashSet;
import java.util.Set;

public class LongestSubString {

    static void main() {

        long startTime = System.nanoTime();
        longestSubstringWithTradditionalApproch("");
        long endTime = System.currentTimeMillis();

        System.out.println("Tradditional Approch required time:"+ (endTime-startTime));

        long x = System.currentTimeMillis();
        longestSubstringWithSlidingWindowApproch("");
        long y = System.currentTimeMillis();

        System.out.println("SlidingWindow Approch required time:"+ (y-x));

    }

    public static void longestSubstringWithTradditionalApproch(String s){
        int max = Integer.MIN_VALUE;
        for (int i = 0; i < s.length(); i++) {
            Set<Character> set = new HashSet<>();
            for (int j = i; j < s.length(); j++) {
                char c = s.charAt(j);
                if (!set.contains(c)) {
                    set.add(c);
                    if(max < set.size()){
                        max = set.size();
                    }
                }
                else {
                    break;
                }
            }
        }
        System.out.println(max);
    }

    public static void longestSubstringWithSlidingWindowApproch(String s){

        int left=0;
        int right=0;
        int max=0;
        Set<Character> set=new HashSet<>();

        while (right<s.length()){
            char c=s.charAt(right);
            char c1=s.charAt(left);
            if(!set.contains(c)){
                set.add(c);
                if(max< set.size()){max= set.size();}
                right++;
            }
            else {
                set.remove(c1);
                left++;
            }
        }

        System.out.println(max);

    }
}
